Fn::Sub:
{
  "widgets": [
    {
      "type": "metric",
      "x": 0,
      "y": 0,
      "width": 12,
      "height": 6,
      "properties": {
        "title": "API Request Count",
        "metrics": [
          [
            "AWS/ApiGateway",
            "Count",
            "ApiName",
            "${ApiName}",
            {
              "stat": "Sum",
              "period": 60
            }
          ]
        ],
        "period": 60,
        "region": "${AWS::Region}",
        "yAxis": {
          "left": {
            "min": 0
          }
        }
      }
    },
    {
      "type": "metric",
      "x": 12,
      "y": 0,
      "width": 12,
      "height": 6,
      "properties": {
        "title": "API Error Rate (5XX)",
        "metrics": [
          [
            "AWS/ApiGateway",
            "5XXError",
            "ApiName",
            "${ApiName}",
            {
              "stat": "Sum",
              "period": 60,
              "color": "#d62728"
            }
          ],
          [
            ".",
            "4XXError",
            ".",
            ".",
            {
              "stat": "Sum",
              "period": 60,
              "color": "#ff7f0e"
            }
          ]
        ],
        "period": 60,
        "region": "${AWS::Region}"
      }
    },
    {
      "type": "metric",
      "x": 0,
      "y": 6,
      "width": 12,
      "height": 6,
      "properties": {
        "title": "Lambda Duration (P50/P95/P99)",
        "metrics": [
          [
            "AWS/Lambda",
            "Duration",
            "FunctionName",
            "${ApiName}-BillingHandler",
            {
              "stat": "p50",
              "period": 60
            }
          ],
          [
            "...",
            {
              "stat": "p95"
            }
          ],
          [
            "...",
            {
              "stat": "p99"
            }
          ]
        ],
        "period": 60,
        "region": "${AWS::Region}"
      }
    },
    {
      "type": "metric",
      "x": 12,
      "y": 6,
      "width": 12,
      "height": 6,
      "properties": {
        "title": "Lambda Invocations & Errors",
        "metrics": [
          [
            "AWS/Lambda",
            "Invocations",
            "FunctionName",
            "${ApiName}-BillingHandler",
            {
              "stat": "Sum",
              "period": 60
            }
          ],
          [
            ".",
            "Errors",
            ".",
            ".",
            {
              "stat": "Sum",
              "period": 60,
              "color": "#d62728"
            }
          ]
        ],
        "period": 60,
        "region": "${AWS::Region}"
      }
    },
    {
      "type": "log",
      "x": 0,
      "y": 12,
      "width": 24,
      "height": 6,
      "properties": {
        "title": "Recent Errors",
        "query": "SOURCE '/aws/lambda/${ApiName}-BillingHandler' | SOURCE '/aws/lambda/${ApiName}-AuthHandler' | fields @timestamp, requestId, tenantId, errorCode, errorMessage | filter level = 'ERROR' | sort @timestamp desc | limit 20",
        "region": "${AWS::Region}"
      }
    },
    {
      "type": "metric",
      "x": 0,
      "y": 18,
      "width": 12,
      "height": 6,
      "properties": {
        "title": "DynamoDB Consumed Capacity",
        "metrics": [
          [
            "AWS/DynamoDB",
            "ConsumedReadCapacityUnits",
            "TableName",
            "Bills",
            {
              "stat": "Sum",
              "period": 60
            }
          ],
          [
            ".",
            "ConsumedWriteCapacityUnits",
            ".",
            ".",
            {
              "stat": "Sum",
              "period": 60
            }
          ]
        ],
        "period": 60,
        "region": "${AWS::Region}"
      }
    },
    {
      "type": "metric",
      "x": 12,
      "y": 18,
      "width": 12,
      "height": 6,
      "properties": {
        "title": "DynamoDB Throttling",
        "metrics": [
          [
            "AWS/DynamoDB",
            "ThrottledRequests",
            "TableName",
            "Bills",
            {
              "stat": "Sum",
              "period": 60,
              "color": "#d62728"
            }
          ],
          [
            ".",
            ".",
            "TableName",
            "Customers",
            {
              "stat": "Sum",
              "period": 60
            }
          ],
          [
            ".",
            ".",
            "TableName",
            "Products",
            {
              "stat": "Sum",
              "period": 60
            }
          ]
        ],
        "period": 60,
        "region": "${AWS::Region}"
      }
    },
    {
      "type": "metric",
      "x": 0,
      "y": 24,
      "width": 12,
      "height": 6,
      "properties": {
        "title": "WAF Blocked Requests",
        "metrics": [
          [
            "AWS/WAFV2",
            "BlockedRequests",
            "WebACL",
            "DukanX-API-WAF",
            {
              "stat": "Sum",
              "period": 60,
              "color": "#d62728"
            }
          ],
          [
            ".",
            "AllowedRequests",
            ".",
            ".",
            {
              "stat": "Sum",
              "period": 60,
              "color": "#2ca02c"
            }
          ]
        ],
        "period": 60,
        "region": "${AWS::Region}"
      }
    },
    {
      "type": "log",
      "x": 12,
      "y": 24,
      "width": 12,
      "height": 6,
      "properties": {
        "title": "Request Trace (by RID)",
        "query": "SOURCE '/aws/lambda/${ApiName}-*' | fields @timestamp, @logStream, requestId, message | filter requestId like /tenant/ | sort @timestamp desc | limit 20",
        "region": "${AWS::Region}"
      }
    }
  ]
}
